import React, { useState, useEffect, useCallback } from 'react';
import Select from 'react-select';
import './CreateCombinedMaterial.css';

const LaborHoursRecord = ({
    fetchAPI,
    apiBaseUrl,
    employees
}) => {
    const [error, setError] = useState(null);
    const [projects, setProjects] = useState([]);
    const [dayRecords, setDayRecords] = useState({});
    const [selectedEmployee, setSelectedEmployee] = useState(null);

    const fetchData = useCallback(async () => {
        try {
            const projectsResponse = await fetchAPI(`${apiBaseUrl}/projectsAPI`);
            setProjects(projectsResponse || []);  // Assuming projectsResponse is directly an array.

            const initialDayRecords = {};
            employees.forEach(employee => {
                initialDayRecords[employee.empid] = { name: employee.name, description: '', start: '', end: '', entries: [] };
            });
            setDayRecords(initialDayRecords);
        } catch (error) {
            console.error('Error fetching data:', error);
            setError(error.message || 'Failed to fetch data');
        }
    }, [fetchAPI, apiBaseUrl, employees]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleChange = (employeeId, field, value) => {
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                [field]: value,
            }
        }));
    };

    const handleAddDayRecord = employeeId => {
        const newDayRecord = { project: '', start: '', end: '' };
        setDayRecords(prevRecords => ({
            ...prevRecords,
            [employeeId]: {
                ...prevRecords[employeeId],
                entries: [...prevRecords[employeeId].entries, newDayRecord]
            }
        }));
    };

    if (error) {
        return <div>Error: {error}</div>;
    }

    return (
        <div className="material-input-form-container">
            <div className="employee-list">
                {employees.map(employee => (
                    <button
                        key={employee.empid}
                        className={`employee-button ${selectedEmployee === employee.empid ? 'active' : ''}`}
                        onClick={() => setSelectedEmployee(employee.empid)}
                    >
                        {employee.name}
                    </button>
                ))}
            </div>
            {selectedEmployee && (
                <div className="material-input-form">
                    <h3>Day Record for {dayRecords[selectedEmployee].name}</h3>
                    <button className="close-popup" onClick={() => setSelectedEmployee(null)}>×</button>
                    <div className="form-row">
                        <div className="form-group">
                            <label>Project:</label>
                            <Select
                                name="project"
                                value={projects.find(project => project.prid === dayRecords[selectedEmployee].project) ? { value: dayRecords[selectedEmployee].project, label: projects.find(project => project.prid === dayRecords[selectedEmployee].project).name } : null}
                                options={projects.map(project => ({
                                    value: project.prid,
                                    label: project.name,
                                }))}
                                onChange={selectedOption => handleChange(selectedEmployee, 'project', selectedOption.value)}
                                placeholder="Select a Project"
                                required
                            />
                        </div>
                        <div className="form-group">
                            <label htmlFor={`start-${selectedEmployee}`}>Start Time</label>
                            <input
                                id={`start-${selectedEmployee}`}
                                type="time"
                                name="start"
                                value={dayRecords[selectedEmployee].start}
                                onChange={e => handleChange(selectedEmployee, 'start', e.target.value)}
                                placeholder="HH:MM"
                                className="form-control"
                            />
                        </div>
                        <div className="form-group">
                            <label htmlFor={`end-${selectedEmployee}`}>End Time</label>
                            <input
                                id={`end-${selectedEmployee}`}
                                type="time"
                                name="end"
                                value={dayRecords[selectedEmployee].end}
                                onChange={e => handleChange(selectedEmployee, 'end', e.target.value)}
                                placeholder="HH:MM"
                                className="form-control"
                            />
                        </div>
                    </div>
                    <button onClick={() => handleAddDayRecord(selectedEmployee)} className="btn btn-primary add-btn">Add Project Record</button>
                    <button className="btn btn-success save-btn">Save Day Record</button>
                </div>
            )}
        </div>
    );
};

export default LaborHoursRecord;
